ALTER TABLE public.stripe_prices ADD CONSTRAINT stripe_prices_price_id_key UNIQUE (price_id);

ON CONFLICT (price_id) DO UPDATE SET
  product_name = EXCLUDED.product_name,
  plan_name = EXCLUDED.plan_name,
  price_name = EXCLUDED.price_name,
  area = EXCLUDED.area,
  mrr = EXCLUDED.mrr,
  updated_at = now();